export const generateStandardPhaseOutput = async (project: Project, phase: Phase, tuningSettings: TuningSettings): Promise<string> => {
    const ai = getAi();
    const baseContext = getBasePromptContext(project);
    const projectContext = getProjectContext(project, phase.id);

    let specificInstruction = "";
    if (phase.name === 'Feasibility Study') {
        specificInstruction = "Conduct a formal Feasibility Study. Analyze technical, economic, legal, operational, and scheduling factors (TELOS). Determine if the project should proceed based on the requirements and constraints provided.";
    } else {
        specificInstruction = `Generate documentation for the ${phase.name} phase.`;
    }

    const systemInstruction = getSystemInstruction(`You are an expert engineer. ${specificInstruction}`, project.developmentMode);
    const userPrompt = `${baseContext}\n${projectContext}\n\n## Current Phase: ${phase.name}\n## Tuning:\n${JSON.stringify(tuningSettings)}`;

    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: FLASH_MODEL,
        contents: userPrompt,
        config: { systemInstruction }
    }));
    return response.text;
};

