export const generateDiagram = async (documentContent: string): Promise<string> => {
    const ai = getAi();
    const orchestratorPrompt = `Create a highly detailed image generation prompt for a technical engineering diagram based on this text:\n\n${documentContent.substring(0, 2000)}`;

    const orchestratorResponse = await ai.models.generateContent({
        model: FLASH_MODEL,
        contents: orchestratorPrompt,
        config: { systemInstruction: "Generate a descriptive prompt for a technical diagram (block diagram, flowchart, or schematic style)." }
    });

    const detailedPrompt = orchestratorResponse.text;
    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: IMAGE_MODEL,
        contents: { parts: [{ text: `Create a clean, professional, high-resolution technical engineering diagram: ${detailedPrompt}` }] },
        config: { imageConfig: { aspectRatio: "16:9" } }
    }));

    for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
        }
    }
    throw new Error("Failed to generate diagram image.");
};

