        {step < 7 && (
            <div className="flex justify-between mt-8 p-6 pt-0 -m-6">
              <Button variant="outline" onClick={step === 1 ? onCancel : prevStep}>{step === 1 ? 'Cancel' : 'Back'}</Button>
              <Button onClick={step === 6 ? createProject : nextStep}>Next</Button>
            </div>
        )}
      </Card>
    </div>
  );
};

