declare const Prism: any;

const md = new Remarkable({
    html: true,
    typographer: true,
    highlight: function (str, lang) {
        if (lang && typeof Prism !== 'undefined' && Prism.languages[lang]) {
            try {
                return Prism.highlight(str, Prism.languages[lang], lang);
            } catch (e) {
                console.error(e);
            }
        }
        return '';
    },
});

interface VersionHistoryProps {
    versions: VersionedOutput[];
    selectedVersion: number;
    onSelectVersion: (version: number) => void;
    onCompare: () => void;
}

const VersionHistory: React.FC<VersionHistoryProps> = ({ versions, selectedVersion, onSelectVersion, onCompare }) => (
    <div className="flex items-center space-x-2 bg-gray-100 dark:bg-charcoal-900/50 p-2 rounded-md overflow-x-auto max-w-full">
        <GitCommit className="w-4 h-4 text-gray-500 flex-shrink-0" />
        <select
            value={selectedVersion}
            onChange={(e) => onSelectVersion(Number(e.target.value))}
            className="text-xs border-gray-300 rounded-md shadow-sm dark:bg-charcoal-700 dark:border-gray-600 focus:ring-brand-primary focus:border-brand-primary min-w-[120px]"
        >
            {versions.map((v) => (
                <option key={v.version} value={v.version}>v{v.version} - {v.reason.substring(0, 20)}...</option>
            ))}
        </select>
        {versions.length > 1 && (
            <Button size="sm" variant="ghost" onClick={onCompare} className="whitespace-nowrap px-1">
                <ArrowRightLeft className="w-3 h-3" />
            </Button>
        )}
    </div>
);

interface PhaseOutputProps {
    phase: Phase;
    onGenerate: (reason: string) => void;
    onSave: (output: string, reason: string) => void;
    isLoading: boolean;
    isEditable?: boolean;
    apiKey: string | null;
    modelName: string;
}

export const PhaseOutput = ({ phase, onGenerate, onSave, isLoading, isEditable = true, apiKey, modelName }: PhaseOutputProps) => {
    const { project } = useProject();
    const [isEditing, setIsEditing] = useState(false);
    const [editedOutput, setEditedOutput] = useState('');
    const [selectedVersionIndex, setSelectedVersionIndex] = useState(phase.outputs.length > 0 ? phase.outputs.length - 1 : -1);
    const [refineText, setRefineText] = useState('');
    const [isRefining, setIsRefining] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const latestVersion = phase.outputs[phase.outputs.length - 1];
    const displayedVersion = phase.outputs[selectedVersionIndex] || latestVersion;

    useEffect(() => {
        const newIndex = phase.outputs.length - 1;
        if (newIndex !== selectedVersionIndex) {
            setSelectedVersionIndex(newIndex);
        }
    }, [phase.outputs.length]);

    const handleSave = () => {
        onSave(editedOutput, 'Manual edit');
        setIsEditing(false);
    };

    const handleRefine = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!refineText.trim() || !project || !displayedVersion) return;
        setIsRefining(true);
        setError(null);
        try {
            const refined = await refinePhaseOutput(project, phase, displayedVersion.content, refineText);
            onSave(refined, `AI Refinement: ${refineText}`);
            setRefineText('');
        } catch (err: any) {
            setError(err.message || "Failed to refine content. The AI may be experiencing high load.");
            console.error(err);
        } finally {
            setIsRefining(false);
        }
    };

    if (!latestVersion) {
        return (
            <Card title="Phase Output" description="AI-generated deliverables for this phase">
                <div className="text-center py-8">
                    <p className="text-gray-600 dark:text-gray-400 mb-4">No output generated yet.</p>
                    <div className="inline-flex flex-col items-center gap-2">
                        <Button onClick={() => onGenerate('Initial generation')} disabled={!apiKey || isLoading}>
                            {isLoading ? <LoaderCircle className="mr-2 w-4 h-4 animate-spin" /> : <Sliders className="mr-2 w-4 h-4" />}
                            Generate Output with AI
                        </Button>
                        <ModelBadge modelName={modelName} />
                    </div>
                </div>
            </Card>
        );
    }

    return (
        <Card title="Phase Output" description="Collaborate with AI to refine this technical documentation">
            <div className="space-y-4">
                <div className="flex justify-between items-center gap-2 flex-wrap">
                    <VersionHistory
                        versions={phase.outputs}
                        selectedVersion={displayedVersion?.version || 0}
                        onSelectVersion={(v) => setSelectedVersionIndex(phase.outputs.findIndex(o => o.version === v))}
                        onCompare={() => {}}
                    />
                    <div className="flex items-center space-x-2">
                        {isEditable && !isEditing && (
                            <Button variant="outline" size="sm" onClick={() => { setEditedOutput(displayedVersion.content); setIsEditing(true); }}>
                                <Edit3 className="mr-2 w-4 h-4" />Edit
                            </Button>
                        )}
                        {isEditing && (
                            <Button variant="ghost" size="sm" onClick={() => setIsEditing(false)}><X className="w-4 h-4"/></Button>
                        )}
                        {!isEditing && (
                            <div className="inline-flex flex-col items-end gap-1">
                                <Button variant="outline" size="sm" onClick={() => onGenerate('Regeneration')} disabled={!apiKey || isLoading}>
                                    {isLoading ? <LoaderCircle className="mr-2 w-4 h-4 animate-spin" /> : <Sliders className="mr-2 w-4 h-4" />}
                                    Full Refresh
                                </Button>
                                <ModelBadge modelName={modelName} />
                            </div>
                        )}
                    </div>
                </div>

                {error && (
                    <div className="p-3 bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-lg text-sm flex items-start gap-2 border border-red-100 dark:border-red-900/50">
                        <AlertCircle className="w-4 h-4 mt-0.5 flex-shrink-0" />
                        <span>{error}</span>
                        <button onClick={() => setError(null)} className="ml-auto hover:opacity-70"><X className="w-4 h-4"/></button>
                    </div>
                )}

                <div className="border rounded-lg overflow-hidden dark:border-gray-700 bg-gray-50 dark:bg-gray-900/50">
                    {isEditing ? (
                        <div className="p-4 space-y-3">
                            <MarkdownEditor value={editedOutput} onChange={setEditedOutput} />
                            <div className="flex justify-end space-x-2">
                                <Button variant="outline" size="sm" onClick={() => setIsEditing(false)}>Cancel</Button>
                                <Button size="sm" onClick={handleSave}><Save className="mr-2 w-4 h-4" />Save Version</Button>
                            </div>
                        </div>
                    ) : (
                        <div className="p-4 overflow-y-auto max-h-[60vh] prose dark:prose-invert max-w-none">
                            {displayedVersion && (
                                <>
                                    {selectedVersionIndex !== phase.outputs.length - 1 && (
                                        <div className="p-2 mb-4 text-xs bg-yellow-100 dark:bg-yellow-900/30 rounded-md text-yellow-800 dark:text-yellow-200 flex items-center">
                                            <Clock className="w-3 h-3 mr-2" /> Viewing past version: {displayedVersion.reason}
                                        </div>
                                    )}
                                    <div dangerouslySetInnerHTML={{ __html: md.render(displayedVersion.content || '') }} />
                                </>
                            )}
                        </div>
                    )}
                </div>

                {!isEditing && (
                    <form onSubmit={handleRefine} className="flex items-center space-x-2 bg-white dark:bg-charcoal-800 border dark:border-charcoal-700 p-2 rounded-lg shadow-sm">
                        <div className="p-1 px-2 text-brand-primary flex items-center">
                            {isRefining ? <LoaderCircle className="w-4 h-4 animate-spin" /> : <Sparkles className="w-5 h-5" />}
                        </div>
                        <input
                            type="text"
                            value={refineText}
                            onChange={(e) => setRefineText(e.target.value)}
                            placeholder="Prompt AI to refine content... (e.g. 'Add a risks section')"
                            className="flex-1 bg-transparent border-none focus:ring-0 text-sm py-1 placeholder-gray-400 dark:placeholder-gray-500"
                            disabled={isRefining || isLoading}
                        />
                        <Button type="submit" size="sm" disabled={isRefining || isLoading || !refineText.trim()} className="!p-2">
                            <Send className="w-4 h-4" />
                        </Button>
                    </form>
                )}
            </div>
        </Card>
    );
};

import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import { Project, User, Phase, Comment, Task } from '../types';

interface ProjectContextType {
    project: Project | null;
    setProject: React.Dispatch<React.SetStateAction<Project | null>>;
    projects: Project[];
    currentUser: User | null;
    setCurrentUser: React.Dispatch<React.SetStateAction<User | null>>;
    theme: string;
    setTheme: (theme: string) => void;

    // Auth & Project list management
    login: (email: string, pass: string) => boolean;
    signup: (name: string, email: string, pass: string) => boolean;
    logout: () => void;

    // Project lifecycle management
    updateProject: (updatedProject: Project) => void;
    addProject: (newProject: Project) => void;
    deleteProject: (projectId: string) => void;
    updateProjectDetails: (projectId: string, updates: { requirements: string, constraints: string }) => void;
    updatePhase: (projectId: string, phaseId: string, updates: Partial<Phase>) => void;
    addComment: (projectId: string, phaseId: string, text: string) => void;
    addTask: (projectId: string, task: Omit<Task, 'id' | 'createdAt'>) => void;
    updateTask: (projectId: string, updatedTask: Task) => void;
}

const ProjectContext = createContext<ProjectContextType | undefined>(undefined);

interface ProjectProviderProps {
    children?: ReactNode;
}

export const ProjectProvider = ({ children }: ProjectProviderProps) => {
    const [project, setProject] = useState<Project | null>(null);
    const [projects, setProjects] = useState<Project[]>([]);
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [theme, setThemeState] = useState(() => {
        if (typeof window === 'undefined') return 'dark';
        return localStorage.getItem('theme') || 'dark';
    });

    const setTheme = (newTheme: string) => {
        if (newTheme === 'dark') {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
        localStorage.setItem('theme', newTheme);
        setThemeState(newTheme);
    };

    useEffect(() => {
        setTheme(theme);
    }, []);

    // Load current user from local storage on initial load (Persistent across restarts)
    useEffect(() => {
        try {
            const savedUser = localStorage.getItem('vibe_currentUser');
            if (savedUser) {
                const user = JSON.parse(savedUser);
                setCurrentUser(user);

                // Load projects for this user
                const savedProjects = localStorage.getItem(`projects_${user.id}`);
                const parsedProjects = savedProjects ? JSON.parse(savedProjects) : [];
                setProjects(parsedProjects);

                // Load active project ID
                const activeProjectId = localStorage.getItem(`activeProject_${user.id}`);
                if (activeProjectId) {
                    const activeProject = parsedProjects.find((p: Project) => p.id === activeProjectId);
                    if (activeProject) setProject(activeProject);
                }
            }
        } catch (error) {
            console.error("Failed to load persistent state:", error);
            setCurrentUser(null);
        }
    }, []);

    // Persist current user and projects whenever they change
    useEffect(() => {
        if (typeof window !== 'undefined') {
            if (currentUser) {
                localStorage.setItem('vibe_currentUser', JSON.stringify(currentUser));
                localStorage.setItem(`projects_${currentUser.id}`, JSON.stringify(projects));
                if (project) {
                    localStorage.setItem(`activeProject_${currentUser.id}`, project.id);
                } else {
                    localStorage.removeItem(`activeProject_${currentUser.id}`);
                }
            } else {
                localStorage.removeItem('vibe_currentUser');
            }
        }
    }, [currentUser, projects, project]);

    const updateProject = (updatedProject: Project) => {
        setProjects(prevProjects => {
            const projectExists = prevProjects.some(p => p.id === updatedProject.id);
            if (projectExists) {
                return prevProjects.map(p => p.id === updatedProject.id ? updatedProject : p);
            } else {
                return [...prevProjects, updatedProject];
            }
        });
        if (project && project.id === updatedProject.id) {
            setProject(updatedProject);
        }
    };

    const addProject = (newProject: Project) => {
        setProjects(prev => [...prev, newProject]);
    };

    const deleteProject = (projectId: string) => {
        setProjects(prev => prev.filter(p => p.id !== projectId));
        if (project?.id === projectId) {
            setProject(null);
        }
    };

    const updateProjectDetails = (projectId: string, updates: { requirements: string, constraints: string }) => {
        const updateFn = (p: Project) => p.id === projectId ? { ...p, ...updates } : p;
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const updatePhase = (projectId: string, phaseId: string, updates: Partial<Phase>) => {
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedPhases = p.phases.map(ph => ph.id === phaseId ? { ...ph, ...updates } : ph);
                return { ...p, phases: updatedPhases };
            }
            return p;
        };
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const addComment = (projectId: string, phaseId: string, text: string) => {
        if (!currentUser) return;
        const newComment: Comment = {
            id: crypto.randomUUID(),
            userId: currentUser.id,
            phaseId, text, createdAt: new Date()
        };
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedComments = { ...p.comments };
                if (!updatedComments[phaseId]) updatedComments[phaseId] = [];
                updatedComments[phaseId].push(newComment);
                return { ...p, comments: updatedComments };
            }
            return p;
        };
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const addTask = (projectId: string, task: Omit<Task, 'id' | 'createdAt'>) => {
         const newTask: Task = { ...task, id: crypto.randomUUID(), createdAt: new Date() };
         const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedTasks = [...(p.tasks || []), newTask];
                return { ...p, tasks: updatedTasks };
            }
            return p;
         };
         setProjects(prev => prev.map(updateFn));
         if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const updateTask = (projectId: string, updatedTask: Task) => {
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedTasks = (p.tasks || []).map(t => t.id === updatedTask.id ? updatedTask : t);
                return { ...p, tasks: updatedTasks };
            }
            return p;
         };
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const login = (email: string, pass: string): boolean => {
        const users: User[] = JSON.parse(localStorage.getItem('vibe_engineering_users') || '[]');
        const user = users.find(u => u.email === email);
        if (user) {
            setCurrentUser(user);
            return true;
        }
        return false;
    };

    const signup = (name: string, email: string, pass: string): boolean => {
        let users: User[] = JSON.parse(localStorage.getItem('vibe_engineering_users') || '[]');
        if (users.some(u => u.email === email)) {
            return false;
        }
        const newUser: User = { 
            id: crypto.randomUUID(), 
            name, 
            email, 
            role: 'Engineer', 
            avatar: '👤' 
        };
        users.push(newUser);
        localStorage.setItem('vibe_engineering_users', JSON.stringify(users));
        setCurrentUser(newUser);
        return true;
    };

    const logout = () => {
        if (currentUser) {
            localStorage.removeItem(`activeProject_${currentUser.id}`);
        }
        setCurrentUser(null);
        setProject(null);
        localStorage.removeItem('vibe_currentUser');
    };

    return (
        <ProjectContext.Provider value={{ 
            project, setProject, 
            projects,
            currentUser,
            setCurrentUser,
            theme, setTheme,
            login, signup, logout,
            updateProject, addProject, deleteProject, updateProjectDetails, updatePhase, addComment, addTask, updateTask
        }}>
            {children}
        </ProjectContext.Provider>
    );
};

export const useProject = (): ProjectContextType => {
    const context = useContext(ProjectContext);
    if (context === undefined) {
        throw new Error('useProject must be used within a ProjectProvider');
    }
    return context;
};

