export const runAutomatedPhaseGeneration = async (project: Project, phase: Phase, onUpdate: any, onToast: any, signal: any): Promise<void> => {
    if (signal.aborted) throw new UserCancelledError();
    onToast(`Automating ${phase.name}...`);
    const output = await generateStandardPhaseOutput(project, phase, phase.tuningSettings);
    if (signal.aborted) throw new UserCancelledError();
    onUpdate({
        phaseId: phase.id,
        phaseUpdates: {
            outputs: [{ version: 1, content: output, reason: 'Automated Generation', createdAt: new Date() }],
            status: 'completed'
        }
    });
};

