import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import { Project, User, Phase, Comment, Task } from '../types';

interface ProjectContextType {
    project: Project | null;
    setProject: React.Dispatch<React.SetStateAction<Project | null>>;
    projects: Project[];
    currentUser: User | null;
    setCurrentUser: React.Dispatch<React.SetStateAction<User | null>>;
    theme: string;
    setTheme: (theme: string) => void;

    // Auth & Project list management
    login: (email: string, pass: string) => boolean;
    signup: (name: string, email: string, pass: string) => boolean;
    logout: () => void;
    updateUserProfile: (updates: Partial<User>) => void;

    // Project lifecycle management
    updateProject: (updatedProject: Project) => void;
    addProject: (newProject: Project) => void;
    deleteProject: (projectId: string) => void;
    updateProjectDetails: (projectId: string, updates: { requirements: string, constraints: string }) => void;
    updatePhase: (projectId: string, phaseId: string, updates: Partial<Phase>) => void;
    addComment: (projectId: string, phaseId: string, text: string) => void;
    addTask: (projectId: string, task: Omit<Task, 'id' | 'createdAt'>) => void;
    updateTask: (projectId: string, updatedTask: Task) => void;
}

const ProjectContext = createContext<ProjectContextType | undefined>(undefined);

interface ProjectProviderProps {
    children?: ReactNode;
}

export const ProjectProvider = ({ children }: ProjectProviderProps) => {
    const [project, setProject] = useState<Project | null>(null);
    const [projects, setProjects] = useState<Project[]>([]);
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [theme, setThemeState] = useState(() => {
        if (typeof window === 'undefined') return 'dark';
        return localStorage.getItem('theme') || 'dark';
    });

    const setTheme = (newTheme: string) => {
        if (newTheme === 'dark') {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
        localStorage.setItem('theme', newTheme);
        setThemeState(newTheme);
    };

    useEffect(() => {
        setTheme(theme);
    }, []);

    // Load current user from local storage on initial load (Persistent across restarts)
    useEffect(() => {
        try {
            const savedUser = localStorage.getItem('vibe_currentUser');
            if (savedUser) {
                const user = JSON.parse(savedUser);
                setCurrentUser(user);

                // Load projects for this user
                const savedProjects = localStorage.getItem(`projects_${user.id}`);
                const parsedProjects = savedProjects ? JSON.parse(savedProjects) : [];
                setProjects(parsedProjects);

                // Load active project ID
                const activeProjectId = localStorage.getItem(`activeProject_${user.id}`);
                if (activeProjectId) {
                    const activeProject = parsedProjects.find((p: Project) => p.id === activeProjectId);
                    if (activeProject) setProject(activeProject);
                }
            }
        } catch (error) {
            console.error("Failed to load persistent state:", error);
            setCurrentUser(null);
        }
    }, []);

    // Persist current user and projects whenever they change
    useEffect(() => {
        if (typeof window !== 'undefined') {
            if (currentUser) {
                localStorage.setItem('vibe_currentUser', JSON.stringify(currentUser));
                localStorage.setItem(`projects_${currentUser.id}`, JSON.stringify(projects));
                if (project) {
                    localStorage.setItem(`activeProject_${currentUser.id}`, project.id);
                } else {
                    localStorage.removeItem(`activeProject_${currentUser.id}`);
                }
            } else {
                localStorage.removeItem('vibe_currentUser');
            }
        }
    }, [currentUser, projects, project]);

    const updateProject = (updatedProject: Project) => {
        setProjects(prevProjects => {
            const projectExists = prevProjects.some(p => p.id === updatedProject.id);
            if (projectExists) {
                return prevProjects.map(p => p.id === updatedProject.id ? updatedProject : p);
            } else {
                return [...prevProjects, updatedProject];
            }
        });
        if (project && project.id === updatedProject.id) {
            setProject(updatedProject);
        }
    };

    const addProject = (newProject: Project) => {
        setProjects(prev => [...prev, newProject]);
    };

    const deleteProject = (projectId: string) => {
        setProjects(prev => prev.filter(p => p.id !== projectId));
        if (project?.id === projectId) {
            setProject(null);
        }
    };

    const updateProjectDetails = (projectId: string, updates: { requirements: string, constraints: string }) => {
        const updateFn = (p: Project) => p.id === projectId ? { ...p, ...updates } : p;
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const updatePhase = (projectId: string, phaseId: string, updates: Partial<Phase>) => {
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedPhases = p.phases.map(ph => ph.id === phaseId ? { ...ph, ...updates } : ph);
                return { ...p, phases: updatedPhases };
            }
            return p;
        };
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const addComment = (projectId: string, phaseId: string, text: string) => {
        if (!currentUser) return;
        const newComment: Comment = {
            id: crypto.randomUUID(),
            userId: currentUser.id,
            phaseId, text, createdAt: new Date()
        };
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedComments = { ...p.comments };
                if (!updatedComments[phaseId]) updatedComments[phaseId] = [];
                updatedComments[phaseId].push(newComment);
                return { ...p, comments: updatedComments };
            }
            return p;
        };
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const addTask = (projectId: string, task: Omit<Task, 'id' | 'createdAt'>) => {
         const newTask: Task = { ...task, id: crypto.randomUUID(), createdAt: new Date() };
         const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedTasks = [...(p.tasks || []), newTask];
                return { ...p, tasks: updatedTasks };
            }
            return p;
         };
         setProjects(prev => prev.map(updateFn));
         if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const updateTask = (projectId: string, updatedTask: Task) => {
        const updateFn = (p: Project) => {
            if (p.id === projectId) {
                const updatedTasks = (p.tasks || []).map(t => t.id === updatedTask.id ? updatedTask : t);
                return { ...p, tasks: updatedTasks };
            }
            return p;
         };
        setProjects(prev => prev.map(updateFn));
        if (project?.id === projectId) setProject(p => p ? updateFn(p) : null);
    };

    const login = (email: string, pass: string): boolean => {
        const users: User[] = JSON.parse(localStorage.getItem('vibe_engineering_users') || '[]');
        const user = users.find(u => u.email === email);
        if (user) {
            setCurrentUser(user);
            return true;
        }
        return false;
    };

    const signup = (name: string, email: string, pass: string): boolean => {
        let users: User[] = JSON.parse(localStorage.getItem('vibe_engineering_users') || '[]');
        if (users.some(u => u.email === email)) {
            return false;
        }
        const newUser: User = { 
            id: crypto.randomUUID(), 
            name, 
            email, 
            role: 'Engineer', 
            avatar: '👤' 
        };
        users.push(newUser);
        localStorage.setItem('vibe_engineering_users', JSON.stringify(users));
        setCurrentUser(newUser);
        return true;
    };

    const updateUserProfile = (updates: Partial<User>) => {
        if (!currentUser) return;
        const updatedUser = { ...currentUser, ...updates };
        setCurrentUser(updatedUser);

        // Update in global users list
        let users: User[] = JSON.parse(localStorage.getItem('vibe_engineering_users') || '[]');
        users = users.map(u => u.id === updatedUser.id ? updatedUser : u);
        localStorage.setItem('vibe_engineering_users', JSON.stringify(users));
    };

    const logout = () => {
        if (currentUser) {
            localStorage.removeItem(`activeProject_${currentUser.id}`);
        }
        setCurrentUser(null);
        setProject(null);
        localStorage.removeItem('vibe_currentUser');
    };

    return (
        <ProjectContext.Provider value={{ 
            project, setProject, 
            projects,
            currentUser,
            setCurrentUser,
            theme, setTheme,
            login, signup, logout, updateUserProfile,
            updateProject, addProject, deleteProject, updateProjectDetails, updatePhase, addComment, addTask, updateTask
        }}>
            {children}
        </ProjectContext.Provider>
    );
};

export const useProject = (): ProjectContextType => {
    const context = useContext(ProjectContext);
    if (context === undefined) {
        throw new Error('useProject must be used within a ProjectProvider');
    }
    return context;
};

import React, { useState } from 'react';
import { X, Save, Download, Upload, User, BrainCircuit, LoaderCircle } from 'lucide-react';
import { useProject } from '../context/ProjectContext';
import { Button, Card } from './ui';
import { ToastMessage } from '../types';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    setToast: (toast: ToastMessage | null) => void;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, setToast }) => {
    const { currentUser, updateUserProfile, project, updateProject } = useProject();
    const [name, setName] = useState(currentUser?.name || '');
    const [email, setEmail] = useState(currentUser?.email || '');
    const [occupation, setOccupation] = useState(currentUser?.occupation || '');
    const [aiModel, setAiModel] = useState(project?.aiModel || 'gemini-3-flash-preview');
    const [isSaving, setIsSaving] = useState(false);

    if (!isOpen) return null;

    const handleSave = () => {
        setIsSaving(true);
        updateUserProfile({ name, email, occupation });
        if (project) {
            updateProject({ ...project, aiModel });
        }
        setToast({ message: 'Settings updated successfully.', type: 'success' });
        setTimeout(() => {
            setIsSaving(false);
            onClose();
        }, 500);
    };

    const handleFullBackup = () => {
        const fullState = {
            currentUser,
            projects: JSON.parse(localStorage.getItem(`projects_${currentUser?.id}`) || '[]'),
            settings: { theme: localStorage.getItem('theme'), aiModel }
        };
        const blob = new Blob([JSON.stringify(fullState, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `vibe_engineer_backup_${new Date().toISOString().split('T')[0]}.json`;
        a.click();
        setToast({ message: 'Full system backup downloaded.', type: 'success' });
    };

    const handleFullRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const state = JSON.parse(event.target?.result as string);
                if (state.currentUser && state.projects) {
                    localStorage.setItem('vibe_currentUser', JSON.stringify(state.currentUser));
                    localStorage.setItem(`projects_${state.currentUser.id}`, JSON.stringify(state.projects));
                    setToast({ message: 'Full system restored. Please reload the page.', type: 'success' });
                    setTimeout(() => window.location.reload(), 1500);
                } else {
                    throw new Error('Invalid backup file structure.');
                }
            } catch (err) {
                setToast({ message: 'Failed to restore backup. Invalid format.', type: 'error' });
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="fixed inset-0 bg-gray-900 bg-opacity-75 flex items-center justify-center z-[200] p-4" onClick={onClose}>
            <Card className="w-full max-w-lg" onClick={e => e.stopPropagation()} noPadding>
                <div className="flex items-center justify-between p-4 border-b dark:border-charcoal-700">
                    <h2 className="text-xl font-bold">App Settings</h2>
                    <button onClick={onClose} className="p-1 rounded-full text-gray-500 hover:bg-gray-100 dark:hover:bg-charcoal-700">
                        <X className="w-6 h-6" />
                    </button>
                </div>
                <div className="p-6 space-y-6">
                    {/* Profile Section */}
                    <div className="space-y-4">
                        <h3 className="text-sm font-semibold text-gray-500 uppercase flex items-center gap-2">
                            <User className="w-4 h-4" /> User Profile
                        </h3>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-medium mb-1">Name</label>
                                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full p-2 border rounded-md dark:bg-charcoal-700 dark:border-gray-600" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium mb-1">Email</label>
                                <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full p-2 border rounded-md dark:bg-charcoal-700 dark:border-gray-600" />
                            </div>
                            <div className="sm:col-span-2">
                                <label className="block text-xs font-medium mb-1">Occupation</label>
                                <input type="text" value={occupation} onChange={e => setOccupation(e.target.value)} placeholder="e.g. Senior Mechanical Engineer" className="w-full p-2 border rounded-md dark:bg-charcoal-700 dark:border-gray-600" />
                            </div>
                        </div>
                    </div>

                    {/* AI Section */}
                    <div className="space-y-4">
                        <h3 className="text-sm font-semibold text-gray-500 uppercase flex items-center gap-2">
                            <BrainCircuit className="w-4 h-4" /> AI Configuration
                        </h3>
                        <div>
                            <label className="block text-xs font-medium mb-1">Gemini Model</label>
                            <select value={aiModel} onChange={e => setAiModel(e.target.value)} className="w-full p-2 border rounded-md dark:bg-charcoal-700 dark:border-gray-600">
                                <option value="gemini-3-flash-preview">Gemini 3 Flash (Fast)</option>
                                <option value="gemini-3-pro-preview">Gemini 3 Pro (Complex Reasoning)</option>
                                <option value="gemini-2.5-flash-lite-latest">Gemini 2.5 Flash Lite</option>
                            </select>
                        </div>
                    </div>

                    {/* Backup & Restore */}
                    <div className="space-y-4">
                        <h3 className="text-sm font-semibold text-gray-500 uppercase">System Maintenance</h3>
                        <div className="grid grid-cols-2 gap-4">
                            <Button variant="outline" size="sm" onClick={handleFullBackup} className="w-full">
                                <Download className="w-4 h-4 mr-2" /> Backup
                            </Button>
                            <label className="w-full">
                                <input type="file" onChange={handleFullRestore} className="hidden" accept=".json" />
                                <div className="flex items-center justify-center w-full px-3 py-2 text-sm border-2 border-dashed rounded-lg cursor-pointer hover:bg-gray-100 dark:hover:bg-charcoal-800/50 dark:border-charcoal-700 border-gray-300 dark:border-gray-600">
                                    <Upload className="w-4 h-4 mr-2" /> Restore
                                </div>
                            </label>
                        </div>
                    </div>

                    <div className="flex justify-end pt-4 border-t dark:border-charcoal-700">
                        <Button onClick={handleSave} disabled={isSaving}>
                            {isSaving ? <LoaderCircle className="w-4 h-4 animate-spin mr-2" /> : <Save className="w-4 h-4 mr-2" />}
                            Save Settings
                        </Button>
                    </div>
                </div>
            </Card>
        </div>
    );
};

