  version: number;
  content: string;
  reason: string;
  createdAt: Date;
}

export interface Sprint {
  id:string;
  name: string;
  description: string;
  status: 'not-started' | 'in-progress' | 'completed';
  deliverables: string[];
  outputs: VersionedOutput[];
  dependencies?: string[];
  notes?: string;
  attachments?: {
    name: string;
    content: string; // base64 encoded
